#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
T mask_array[MAX_MASK_WIDTH];

template<typename T>
void conv1d(const T * __restrict__ in,
            T * __restrict__ out,
            const int input_width,
            const int mask_width,
            const T * __restrict__ d_mask)
{
    #pragma omp parallel for
    for (int i = 0; i < input_width; i++) {
        T s = 0;
        int start = i - mask_width / 2;
        for (int j = 0; j < mask_width; j++) {
            if (start + j >= 0 && start + j < input_width) {
                s += in[start + j] * d_mask[j];
            }
        }
        out[i] = s;
    }
}

template<typename T>
void conv1d_tiled(const T *__restrict__ in,
                  T *__restrict__ out,
                  const int input_width,
                  const int mask_width,
                  const T * __restrict__ d_mask,
                  int block_size)
{
    int n = mask_width / 2;
    int num_blocks = (input_width + block_size - 1) / block_size;

    #pragma omp parallel for
    for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
        int start_idx = block_idx * block_size;
        int end_idx = (block_idx + 1) * block_size;
        if (end_idx > input_width) end_idx = input_width;

        int local_size = end_idx - start_idx;

        T tile[MAX_BLOCK_SIZE + MAX_MASK_WIDTH];

        int halo_left_start = (block_idx - 1) * block_size;
        int halo_left_end = start_idx;

        for (int i = 0; i < local_size; i++) {
            tile[n + i] = in[start_idx + i];
        }

        if (block_idx > 0) {
            for (int i = 0; i < n; i++) {
                int idx = halo_left_start + (local_size - n + i);
                if (idx >= 0 && idx < start_idx) {
                    tile[i] = in[idx];
                } else {
                    tile[i] = 0;
                }
            }
        } else {
            for (int i = 0; i < n; i++) {
                tile[i] = 0;
            }
        }

        int halo_right_start = end_idx;
        int halo_right_end = (block_idx + 1) * block_size;

        if (block_idx < num_blocks - 1 || end_idx < input_width) {
            for (int i = 0; i < n; i++) {
                int idx = end_idx + i;
                if (idx >= 0 && idx < input_width) {
                    tile[local_size + n + i] = in[idx];
                } else {
                    tile[local_size + n + i] = 0;
                }
            }
        } else {
            for (int i = 0; i < n; i++) {
                tile[local_size + n + i] = 0;
            }
        }

        for (int i = 0; i < local_size; i++) {
            int global_i = start_idx + i;
            T s = 0;
            for (int j = 0; j < mask_width; j++) {
                s += tile[i + j] * d_mask[j];
            }
            out[global_i] = s;
        }
    }
}

template<typename T>
void conv1d_tiled_caching(const T *__restrict__ in,
                          T *__restrict__ out,
                          const int input_width,
                          const int mask_width,
                          const T * __restrict__ d_mask,
                          int block_size)
{
    int num_blocks = (input_width + block_size - 1) / block_size;

    #pragma omp parallel for
    for (int block_idx = 0; block_idx < num_blocks; block_idx++) {
        int start_idx = block_idx * block_size;
        int end_idx = (block_idx + 1) * block_size;
        if (end_idx > input_width) end_idx = input_width;

        int local_size = end_idx - start_idx;

        T tile[MAX_BLOCK_SIZE];

        for (int i = 0; i < local_size; i++) {
            tile[i] = in[start_idx + i];
        }

        int this_tile_start = start_idx;
        int next_tile_start = end_idx;
        int half_mask = mask_width / 2;

        for (int i = 0; i < local_size; i++) {
            int global_i = start_idx + i;
            int start = global_i - half_mask;
            T s = 0;
            for (int j = 0; j < mask_width; j++) {
                int in_index = start + j;
                if (in_index >= 0 && in_index < input_width) {
                    if (in_index >= this_tile_start && in_index < next_tile_start) {
                        s += tile[in_index - this_tile_start] * d_mask[j];
                    } else {
                        s += in[in_index] * d_mask[j];
                    }
                }
            }
            out[global_i] = s;
        }
    }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes); 
  b = (T *)malloc(size_bytes); 

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1; 

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a, *d_b;
  d_a = (T *)malloc(size_bytes);
  d_b = (T *)malloc(size_bytes);

  memcpy(d_a, a, size_bytes);

  T d_mask[MAX_MASK_WIDTH];
  memcpy(d_mask, h_mask, mask_width * sizeof(T));


  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d<T>(d_a, d_b, input_width, mask_width, d_mask);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    memcpy(b, d_b, size_bytes);
    reference(a, b, h_mask, input_width, mask_width);
  }


  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled<T>(d_a, d_b, input_width, mask_width, d_mask, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    memcpy(b, d_b, size_bytes);
    reference(a, b, h_mask, input_width, mask_width);
  }


  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_caching<T>(d_a, d_b, input_width, mask_width, d_mask, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);
    memcpy(b, d_b, size_bytes);
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  free(d_a);
  free(d_b);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width); 

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
